CREATE DATABASE IF NOT EXISTS szerviz_nyilvantarto CHARACTER SET utf8mb4 COLLATE utf8mb4_hungarian_ci;
USE szerviz_nyilvantarto;

DROP TABLE IF EXISTS work_orders;
DROP TABLE IF EXISTS maintenance_records;
DROP TABLE IF EXISTS appointments;
DROP TABLE IF EXISTS equipment;
DROP TABLE IF EXISTS customers;

CREATE TABLE customers (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(120) NOT NULL,
    phone VARCHAR(40) NOT NULL,
    email VARCHAR(120) NOT NULL,
    address VARCHAR(180) NOT NULL,
    notes TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;

CREATE TABLE equipment (
    id INT AUTO_INCREMENT PRIMARY KEY,
    customer_id INT NOT NULL,
    type ENUM('kazĂˇn', 'klĂ­ma', 'hĹ‘szivattyĂş', 'egyĂ©b') NOT NULL,
    name VARCHAR(120) NOT NULL,
    serial_number VARCHAR(80) NOT NULL,
    installation_date DATE NOT NULL,
    next_maintenance_date DATE NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_equipment_customer
        FOREIGN KEY (customer_id) REFERENCES customers(id)
        ON DELETE CASCADE
) ENGINE=InnoDB;

CREATE TABLE appointments (
    id INT AUTO_INCREMENT PRIMARY KEY,
    customer_id INT NOT NULL,
    equipment_id INT NULL,
    appointment_at DATETIME NOT NULL,
    service_type VARCHAR(100) NOT NULL,
    status ENUM('tervezett', 'folyamatban', 'kĂ©sz', 'lemondva') NOT NULL DEFAULT 'tervezett',
    notes TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_appointment_customer
        FOREIGN KEY (customer_id) REFERENCES customers(id)
        ON DELETE CASCADE,
    CONSTRAINT fk_appointment_equipment
        FOREIGN KEY (equipment_id) REFERENCES equipment(id)
        ON DELETE SET NULL
) ENGINE=InnoDB;

CREATE TABLE maintenance_records (
    id INT AUTO_INCREMENT PRIMARY KEY,
    equipment_id INT NOT NULL,
    service_date DATE NOT NULL,
    technician VARCHAR(100) NOT NULL,
    description TEXT NOT NULL,
    parts_used TEXT,
    cost DECIMAL(10,2) NOT NULL DEFAULT 0,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_maintenance_equipment
        FOREIGN KEY (equipment_id) REFERENCES equipment(id)
        ON DELETE CASCADE
) ENGINE=InnoDB;

CREATE TABLE work_orders (
    id INT AUTO_INCREMENT PRIMARY KEY,
    appointment_id INT NOT NULL,
    work_order_number VARCHAR(40) NOT NULL UNIQUE,
    work_summary TEXT NOT NULL,
    materials TEXT,
    customer_signature VARCHAR(120),
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_work_order_appointment
        FOREIGN KEY (appointment_id) REFERENCES appointments(id)
        ON DELETE CASCADE
) ENGINE=InnoDB;

CREATE INDEX idx_equipment_next_maintenance ON equipment(next_maintenance_date);
CREATE INDEX idx_appointments_time ON appointments(appointment_at);






SELECT type, COUNT(*) AS darab FROM equipment GROUP BY type ORDER BY type;
